    23→#ifndef THIRD_PARTY_BLINK_RENDERER_CORE_CSS_RESOLVER_STYLE_RESOLVER_H_
    24→#define THIRD_PARTY_BLINK_RENDERER_CORE_CSS_RESOLVER_STYLE_RESOLVER_H_
    25→
    26→#include "base/gtest_prod_util.h"
    27→#include "third_party/blink/renderer/core/animation/interpolation.h"
    28→#include "third_party/blink/renderer/core/animation/property_handle.h"
    29→#include "third_party/blink/renderer/core/core_export.h"
    30→#include "third_party/blink/renderer/core/css/color_scheme_flags.h"
    31→#include "third_party/blink/renderer/core/css/css_position_try_rule.h"
    32→#include "third_party/blink/renderer/core/css/element_rule_collector.h"
    33→#include "third_party/blink/renderer/core/css/resolver/matched_properties_cache.h"
    34→#include "third_party/blink/renderer/core/css/resolver/style_builder.h"
    35→#include "third_party/blink/renderer/core/css/selector_checker.h"
    36→#include "third_party/blink/renderer/core/css/selector_filter.h"
    37→#include "third_party/blink/renderer/core/css/style_request.h"
    38→#include "third_party/blink/renderer/core/style/filter_operations.h"
    39→#include "third_party/blink/renderer/platform/heap/collection_support/heap_hash_map.h"
    40→#include "third_party/blink/renderer/platform/heap/garbage_collected.h"
    41→#include "third_party/blink/renderer/platform/wtf/deque.h"
    42→
    43→namespace blink {
    44→
    45→class CompositorKeyframeValue;
    46→class ContainerSelector;
    47→class CSSPropertyValueSet;
    48→class CSSValue;
    49→class Document;
    50→class Element;
    51→class Font;
    52→class Interpolation;
    53→class MatchResult;
    54→class PageMarginsStyle;
    55→class PropertyHandle;
    56→class StyleCascade;
    57→class StyleRecalcContext;
    58→class StyleRuleUsageTracker;
    59→
    60→// This class selects a ComputedStyle for a given element in a document based on
    61→// the document's collection of stylesheets (user styles, author styles, UA
    62→// style). There is a 1-1 relationship of StyleResolver and Document.
    63→class CORE_EXPORT StyleResolver final : public GarbageCollected<StyleResolver> {
    64→ public:
    65→  explicit StyleResolver(Document&);
    66→  StyleResolver(const StyleResolver&) = delete;
    67→  StyleResolver& operator=(const StyleResolver&) = delete;
    68→  ~StyleResolver();
    69→  void Dispose();
    70→
    71→  const ComputedStyle* ResolveStyle(Element*,
    72→                                    const StyleRecalcContext&,
    73→                                    const StyleRequest& = StyleRequest());
    74→
    75→  // Return a reference to the initial style singleton.
    76→  const ComputedStyle& InitialStyle() const;
    77→
    78→  // Create a new ComputedStyleBuilder based on the initial style singleton.
    79→  ComputedStyleBuilder CreateComputedStyleBuilder() const;
    80→
    81→  // Create a new ComputedStyleBuilder inheriting from the given style.
    82→  ComputedStyleBuilder CreateComputedStyleBuilderInheritingFrom(
    83→      const ComputedStyle& parent_style) const;
    84→
    85→  // Create a ComputedStyle for initial styles to be used as the basis for the
    86→  // root element style. In addition to initial values things like zoom, font,
    87→  // forced color mode etc. is set.
    88→  ComputedStyleBuilder InitialStyleBuilderForElement() const;
    89→  const ComputedStyle* InitialStyleForElement() const;
    90→
    91→  float InitialZoom() const;
    92→
    93→  static CompositorKeyframeValue* CreateCompositorKeyframeValueSnapshot(
    94→      Element&,
    95→      const ComputedStyle& base_style,
    96→      const ComputedStyle* parent_style,
    97→      const PropertyHandle&,
    98→      const CSSValue*,
    99→      double offset);
   100→
   101→  // Calculate computed style for a given page index and name.
   102→  //
   103→  // An optional scale factor may be supplied, which means that the 'zoom'
   104→  // property will be set to this value. This is used to scale borders etc. when
   105→  // the page border box needs to be scaled to match the scale factor used by
   106→  // layout. This should only be used when computing style for the page border
   107→  // box. The resulting margins should be ignored in that case.
   108→  //
   109→  // If ignore_author_style is false, only the input print job settings will be
   110→  // honored (to get default size and margins, and nothing else).
   111→  const ComputedStyle* StyleForPage(uint32_t page_index,
   112→                                    const AtomicString& page_name,
   113→                                    float page_fitting_scale = 1.0,
   114→                                    bool ignore_author_style = false);
   115→
   116→  // Calculate computed style for all 16 @page margin boxes for a given page
   117→  // index and name.
   118→  //
   119→  // Page margin contexts inherit from the page context (page_style).
   120→  void StyleForPageMargins(const ComputedStyle& page_style,
   121→                           uint32_t page_index,
   122→                           const AtomicString& page_name,
   123→                           PageMarginsStyle*);
   124→
   125→  // Trigger loading of resources only needed by printing (such as @page
   126→  // backgrounds, for instance).
   127→  void LoadPaginationResources();
   128→
   129→  const ComputedStyle* StyleForText(Text*);
   130→  const ComputedStyle* StyleForViewport();
   131→  // Returns `ComputedStyle` for rendering initial letter text.
   132→  // `initial_letter_box_style` should have non-normal `initial-letter`
   133→  // property.
   134→  const ComputedStyle* StyleForInitialLetterText(
   135→      const ComputedStyle& initial_letter_box_style,
   136→      const ComputedStyle& paragraph_style);
   137→
   138→  // Propagate computed values from the root or body element to the viewport
   139→  // when specified to do so.
   140→  void PropagateStyleToViewport();
   141→
   142→  // Create ComputedStyle for anonymous boxes.
   143→  ComputedStyleBuilder CreateAnonymousStyleBuilderWithDisplay(
   144→      const ComputedStyle& parent_style,
   145→      EDisplay);
   146→  const ComputedStyle* CreateAnonymousStyleWithDisplay(
   147→      const ComputedStyle& parent_style,
   148→      EDisplay display);
   149→
   150→  // Create ComputedStyle for anonymous wrappers between text boxes and
   151→  // display:contents elements.
   152→  const ComputedStyle* CreateInheritedDisplayContentsStyleIfNeeded(
   153→      const ComputedStyle& parent_style,
   154→      const ComputedStyle& layout_parent_style);
   155→
   156→  // TODO(esprehn): StyleResolver should probably not contain tree walking
   157→  // state, instead we should pass a context object during recalcStyle.
   158→  SelectorFilter& GetSelectorFilter() { return selector_filter_; }
   159→
   160→  struct FindKeyframesRuleResult {
   161→    StyleRuleKeyframes* rule = nullptr;
   162→    const TreeScope* tree_scope = nullptr;
   163→    STACK_ALLOCATED();
   164→  };
   165→  FindKeyframesRuleResult FindKeyframesRule(const Element*,
   166→                                            const Element* animating_element,
   167→                                            const AtomicString& animation_name);
   168→
   169→  // These methods will give back the set of rules that matched for a given
   170→  // element (or a pseudo-element).
   171→  enum CSSRuleFilter {
   172→    kUACSSRules = 1 << 1,
   173→    kUserCSSRules = 1 << 2,
   174→    kAuthorCSSRules = 1 << 3,
   175→    kUAAndUserCSSRules = kUACSSRules | kUserCSSRules,
   176→    kAllButUACSSRules = kUserCSSRules | kAuthorCSSRules,
   177→    kAllCSSRules = kUAAndUserCSSRules | kAuthorCSSRules,
   178→  };
   179→  RuleIndexList* CssRulesForElement(Element*,
   180→                                    unsigned rules_to_include = kAllCSSRules);
   181→  RuleIndexList* PseudoCSSRulesForElement(
   182→      Element*,
   183→      PseudoId,
   184→      const AtomicString& view_transition_name,
   185→      unsigned rules_to_include = kAllCSSRules);
   186→  // Note that StyleRulesForElement will behave as if all links are
   187→  // unvisited; the :visited pseudo class will never match.
   188→  StyleRuleList* StyleRulesForElement(Element*, unsigned rules_to_include);
   189→  HeapHashMap<CSSPropertyName, Member<const CSSValue>> CascadedValuesForElement(
   190→      Element*,
   191→      PseudoId);
   192→
   193→  Element* FindContainerForElement(Element*,
   194→                                   const ContainerSelector&,
   195→                                   const TreeScope* selector_tree_scope);
   196→
   197→  Font ComputeFont(Element&, const ComputedStyle&, const CSSPropertyValueSet&);
   198→
   199→  // FIXME: Rename to reflect the purpose, like didChangeFontSize or something.
   200→  void InvalidateMatchedPropertiesCache();
   201→
   202→  void SetResizedForViewportUnits();
   203→  void ClearResizedForViewportUnits();
   204→  bool WasViewportResized() const { return was_viewport_resized_; }
   205→
   206→  void SetRuleUsageTracker(StyleRuleUsageTracker*);
   207→  void UpdateMediaType();
   208→
   209→  static bool CanReuseBaseComputedStyle(const StyleResolverState& state);
   210→
   211→  static const CSSValue* ComputeValue(Element* element,
   212→                                      const CSSPropertyName&,
   213→                                      const CSSValue&);
   214→  // Resolves a single CSSValue in the context of some element's computed style.
   215→  //
   216→  // This is intended for use by the Inspector Agent.
   217→  static const CSSValue* ResolveValue(Element& element,
   218→                                      const ComputedStyle& style,
   219→                                      const CSSPropertyName&,
   220→                                      const CSSValue&);
   221→
   222→  // Compute FilterOperations from the specified CSSValue, using the provided
   223→  // Font to resolve any font-relative units.
   224→  //
   225→  // Triggers loading of any external references held by |CSSValue|.
   226→  FilterOperations ComputeFilterOperations(Element*,
   227→                                           const Font&,
   228→                                           const CSSValue&);
   229→
   230→  const ComputedStyle* StyleForInterpolations(
   231→      Element& element,
   232→      ActiveInterpolationsMap& animations);
   233→
   234→  // When updating transitions, the "before change style" is the style from
   235→  // the previous style change with the addition of all declarative animations
   236→  // ticked to the current time. Ticking the animations is required to ensure
   237→  // smooth retargeting of transitions.
   238→  // https://drafts.csswg.org/css-transitions-1/#before-change-style
   239→  const ComputedStyle* BeforeChangeStyleForTransitionUpdate(
   240→      Element& element,
   241→      const ComputedStyle& base_style,
   242→      ActiveInterpolationsMap& transition_interpolations);
   243→
   244→  StyleRulePositionTry* ResolvePositionTryRule(const TreeScope* tree_scope,
   245→                                               AtomicString position_try_name);
   246→
   247→  // Check if the BODY or HTML element's display or containment stops
   248→  // propagation of BODY style to HTML and viewport.
   249→  bool ShouldStopBodyPropagation(const Element& body_or_html);
   250→
   251→  // If enabled, will attempt to count the number of bytes used by the
   252→  // generated ComputedStyle objects. Note that most of the fast paths
   253→  // (e.g. inline incremental style) and the non-element styles
   254→  // (e.g. @page) are not accounted for. However, the effect of the MPC
   255→  // should be correctly modeled. Note that there is a significant
   256→  // CPU overhead through this, and it will also allocate a fairly large
   257→  // amount of temporary GC memory for the diffing.
   258→  void SetCountComputedStyleBytes(bool enabled) {
   259→    count_computed_style_bytes_ = enabled;
   260→    computed_style_bytes_used_ = 0;
   261→  }
   262→  size_t GetComputedStyleBytesUsed() const {
   263→    DCHECK(count_computed_style_bytes_);
   264→    return computed_style_bytes_used_;
   265→  }
   266→
   267→  void Trace(Visitor*) const;
   268→
   269→ private:
   270→  // Creates a new ComputedStyle, either cloning an existing one
   271→  // or combining two different ones (see the comment on
   272→  // ApplyBaseStyleNoCache() for more details).
   273→  void InitStyle(Element& element,
   274→                 const StyleRequest&,
   275→                 const ComputedStyle& source_for_noninherited,
   276→                 const ComputedStyle* parent_style,
   277→                 StyleResolverState& state);
   278→
   279→  void ApplyBaseStyle(Element* element,
   280→                      const StyleRecalcContext&,
   281→                      const StyleRequest&,
   282→                      StyleResolverState& state,
   283→                      StyleCascade& cascade);
   284→  void ApplyBaseStyleNoCache(Element* element,
   285→                             const StyleRecalcContext&,
   286→                             const StyleRequest&,
   287→                             StyleResolverState& state,
   288→                             StyleCascade& cascade);
   289→  void ApplyInterpolations(StyleResolverState& state,
   290→                           StyleCascade& cascade,
   291→                           ActiveInterpolationsMap& interpolations);
   292→
   293→  void AddMatchedRulesToTracker(const ElementRuleCollector&);
   294→
   295→  void CollectPseudoRulesForElement(const Element&,
   296→                                    ElementRuleCollector&,
   297→                                    PseudoId,
   298→                                    const AtomicString& view_transition_name,
   299→                                    unsigned rules_to_include);
   300→  void MatchUARules(const Element&, ElementRuleCollector&);
   301→  void MatchUserRules(ElementRuleCollector&);
   302→  void MatchPresentationalHints(StyleResolverState&, ElementRuleCollector&);
   303→  // This matches `::part` selectors. It looks in ancestor scopes as far as
   304→  // part mapping requires.
   305→  void MatchPseudoPartRules(const Element&,
   306→                            ElementRuleCollector&,
   307→                            bool for_shadow_pseudo = false);
   308→  void MatchPseudoPartRulesForUAHost(const Element&, ElementRuleCollector&);
   309→  void MatchPositionTryRules(ElementRuleCollector&);
   310→  void MatchAuthorRules(const Element&, ElementRuleCollector&);
   311→  void MatchAllRules(StyleResolverState&,
   312→                     ElementRuleCollector&,
   313→                     bool include_smil_properties);
   314→  void ApplyMathMLCustomStyleProperties(Element*, StyleResolverState&);
   315→
   316→  struct CacheSuccess {
   317→    STACK_ALLOCATED();
   318→
   319→   public:
   320→    bool is_inherited_cache_hit;
   321→    bool is_non_inherited_cache_hit;
   322→    MatchedPropertiesCache::Key key;
   323→    const CachedMatchedProperties* cached_matched_properties;
   324→
   325→    CacheSuccess(bool is_inherited_cache_hit,
   326→                 bool is_non_inherited_cache_hit,
   327→                 MatchedPropertiesCache::Key key,
   328→                 const CachedMatchedProperties* cached_matched_properties)
   329→        : is_inherited_cache_hit(is_inherited_cache_hit),
   330→          is_non_inherited_cache_hit(is_non_inherited_cache_hit),
   331→          key(key),
   332→          cached_matched_properties(cached_matched_properties) {}
   333→
   334→    bool IsFullCacheHit() const {
   335→      return is_inherited_cache_hit && is_non_inherited_cache_hit;
   336→    }
   337→    bool ShouldApplyInheritedOnly() const {
   338→      return is_non_inherited_cache_hit && !is_inherited_cache_hit;
   339→    }
   340→    void SetFailed() {
   341→      is_inherited_cache_hit = false;
   342→      is_non_inherited_cache_hit = false;
   343→    }
   344→    bool EffectiveZoomChanged(const ComputedStyleBuilder&) const;
   345→    bool FontChanged(const ComputedStyleBuilder&) const;
   346→    bool InheritedVariablesChanged(const ComputedStyleBuilder&) const;
   347→    bool LineHeightChanged(const ComputedStyleBuilder&) const;
   348→    bool IsUsableAfterApplyInheritedOnly(const ComputedStyleBuilder&) const;
   349→  };
   350→
   351→  CacheSuccess ApplyMatchedCache(StyleResolverState&,
   352→                                 const StyleRequest&,
   353→                                 const MatchResult&);
   354→  void MaybeAddToMatchedPropertiesCache(StyleResolverState&,
   355→                                        const CacheSuccess&);
   356→
   357→  void ApplyPropertiesFromCascade(StyleResolverState&,
   358→                                  StyleCascade& cascade,
   359→                                  CacheSuccess cache_success);
   360→
   361→  bool ApplyAnimatedStyle(StyleResolverState&, StyleCascade&);
   362→  void ApplyAnchorData(StyleResolverState&);
   363→
   364→  void ApplyCallbackSelectors(StyleResolverState&);
   365→  void ApplyDocumentRulesSelectors(StyleResolverState&, ContainerNode* scope);
   366→  StyleRuleList* CollectMatchingRulesFromUnconnectedRuleSet(
   367→      StyleResolverState&,
   368→      RuleSet*,
   369→      ContainerNode* scope);
   370→
   371→  Document& GetDocument() const { return *document_; }
   372→
   373→  bool IsForcedColorsModeEnabled() const;
   374→
   375→  template <typename Functor>
   376→  void ForEachUARulesForElement(const Element& element,
   377→                                ElementRuleCollector* collector,
   378→                                Functor& func) const;
   379→
   380→  MatchedPropertiesCache matched_properties_cache_;
   381→
   382→  // Both these members are on a hot-path for creating ComputedStyle objects.
   383→  const subtle::UncompressedMember<const ComputedStyle> initial_style_;
   384→  const subtle::UncompressedMember<const ComputedStyle> initial_style_for_img_;
   385→  SelectorFilter selector_filter_;
   386→
   387→  Member<Document> document_;
   388→  Member<StyleRuleUsageTracker> tracker_;
   389→
   390→  // See SetCountComputedStyleBytes().
   391→  bool count_computed_style_bytes_ = false;
   392→  size_t computed_style_bytes_used_ = 0;
   393→
   394→  bool print_media_type_ = false;
   395→  bool was_viewport_resized_ = false;
   396→
   397→  friend class StyleResolverTest;
   398→  FRIEND_TEST_ALL_PREFIXES(StyleResolverTest, TreeScopedReferences);
   399→};
   400→
   401→}  // namespace blink
   402→
   403→#endif  // THIRD_PARTY_BLINK_RENDERER_CORE_CSS_RESOLVER_STYLE_RESOLVER_H_
   404→

