    23→namespace blink {
    24→
    25→class JSONArray;
    26→
    27→// A container for a list of display items of various types.
    28→class PLATFORM_EXPORT DisplayItemList {
    29→  DISALLOW_NEW();
    30→
    31→ public:
    32→  DisplayItemList() = default;
    33→  ~DisplayItemList() { clear(); }
    34→
    35→  DisplayItemList(const DisplayItemList&) = delete;
    36→  DisplayItemList& operator=(const DisplayItemList&) = delete;
    37→  DisplayItemList(DisplayItemList&&) = delete;
    38→  DisplayItemList& operator=(DisplayItemList&&) = delete;
    39→
    40→  void ReserveCapacity(wtf_size_t initial_capacity) {
    41→    items_.reserve(initial_capacity);
    42→  }
    43→
    44→  void clear();
    45→
    46→  // This private section is before the public APIs because some inline public
    47→  // methods depend on the private definitions.
    48→ private:
    49→  // Declares itself as a forward iterator, but also supports a few more
    50→  // things. The whole random access iterator interface is a bit much.
    51→  template <typename BaseIterator, typename ItemType>
    52→  class IteratorWrapper {
    53→    DISALLOW_NEW();
    54→
    55→   public:
    56→    using iterator_category = std::forward_iterator_tag;
    57→    using value_type = ItemType;
    58→    using difference_type = std::ptrdiff_t;
    59→    using pointer = ItemType*;
    60→    using reference = ItemType&;
    61→
    62→    IteratorWrapper() = default;
    63→    explicit IteratorWrapper(const BaseIterator& it) : it_(it) {}
    64→
    65→    bool operator==(const IteratorWrapper& other) const {
    66→      return it_ == other.it_;
    67→    }
    68→    bool operator!=(const IteratorWrapper& other) const {
    69→      return it_ != other.it_;
    70→    }
    71→    bool operator<(const IteratorWrapper& other) const {
    72→      return it_ < other.it_;
    73→    }
    74→    ItemType& operator*() const { return reinterpret_cast<ItemType&>(*it_); }
    75→    ItemType* operator->() const { return &operator*(); }
    76→    IteratorWrapper operator+(std::ptrdiff_t n) const {
    77→      return IteratorWrapper(it_ + n);
    78→    }
    79→    IteratorWrapper operator++(int) {
    80→      IteratorWrapper tmp = *this;
    81→      ++it_;
    82→      return tmp;
    83→    }
    84→    std::ptrdiff_t operator-(const IteratorWrapper& other) const {
    85→      return it_ - other.it_;
    86→    }
    87→    IteratorWrapper& operator++() {
    88→      ++it_;
    89→      return *this;
    90→    }
    91→
    92→   private:
    93→    BaseIterator it_;
    94→  };
    95→
    96→  // kAlignment must be a multiple of alignof(derived display item) for each
    97→  // derived display item; the ideal value is the least common multiple.
    98→  // The validity of kAlignment and kMaxItemSize are checked in
    99→  // AllocateAndConstruct().
   100→  static constexpr wtf_size_t kAlignment = alignof(ScrollbarDisplayItem);
   101→  static constexpr wtf_size_t kMaxItemSize = sizeof(ScrollbarDisplayItem);
   102→
   103→  struct ItemSlot {
   104→    alignas(kAlignment) uint8_t data[kMaxItemSize];
   105→    DISALLOW_NEW();
   106→  };
   107→  using ItemVector = Vector<ItemSlot>;
   108→
   109→ public:
   110→  using value_type = DisplayItem;
   111→  using iterator = IteratorWrapper<ItemVector::iterator, DisplayItem>;
   112→  using const_iterator =
   113→      IteratorWrapper<ItemVector::const_iterator, const DisplayItem>;
   114→  iterator begin() { return iterator(items_.begin()); }
   115→  iterator end() { return iterator(items_.end()); }
   116→  const_iterator begin() const { return const_iterator(items_.begin()); }
   117→  const_iterator end() const { return const_iterator(items_.end()); }
   118→
   119→  DisplayItem& front() { return *begin(); }
   120→  const DisplayItem& front() const { return *begin(); }
   121→  DisplayItem& back() {
   122→    DCHECK(size());
   123→    return (*this)[size() - 1];
   124→  }
   125→  const DisplayItem& back() const {
   126→    DCHECK(size());
   127→    return (*this)[size() - 1];
   128→  }
   129→
   130→  DisplayItem& operator[](wtf_size_t index) { return *(begin() + index); }
   131→  const DisplayItem& operator[](wtf_size_t index) const {
   132→    return *(begin() + index);
   133→  }
   134→
   135→  wtf_size_t size() const { return items_.size(); }
   136→  bool IsEmpty() const { return !size(); }
   137→
   138→  size_t MemoryUsageInBytes() const {
   139→    return sizeof(*this) + items_.CapacityInBytes();
   140→  }
   141→
   142→  // Useful for iterating with a range-based for loop.
   143→  template <typename Iterator>
   144→  class Range {
   145→    DISALLOW_NEW();
   146→
   147→   public:
   148→    Range(const Iterator& begin, const Iterator& end)
   149→        : begin_(begin), end_(end) {}
   150→    Iterator begin() const { return begin_; }
   151→    Iterator end() const { return end_; }
   152→    wtf_size_t size() const {
   153→      return base::checked_cast<wtf_size_t>(end_ - begin_);
   154→    }
   155→
   156→    // To meet the requirement of gmock ElementsAre().
   157→    using value_type = DisplayItem;
   158→    using const_iterator = DisplayItemList::const_iterator;
   159→
   160→   private:
   161→    Iterator begin_;
   162→    Iterator end_;
   163→  };
   164→
   165→  // In most cases, we should use PaintChunkSubset::Iterator::DisplayItems()
   166→  // instead of these.
   167→  Range<iterator> ItemsInRange(wtf_size_t begin_index, wtf_size_t end_index) {
   168→    return Range<iterator>(begin() + begin_index, begin() + end_index);
   169→  }
   170→  Range<const_iterator> ItemsInRange(wtf_size_t begin_index,
   171→                                     wtf_size_t end_index) const {
   172→    return Range<const_iterator>(begin() + begin_index, begin() + end_index);
   173→  }
   174→
   175→  template <class DerivedItemType, typename... Args>
   176→  DerivedItemType& AllocateAndConstruct(Args&&... args) {
   177→    static_assert(WTF::IsSubclass<DerivedItemType, DisplayItem>::value,
   178→                  "Must use subclass of DisplayItem.");
   179→    static_assert(sizeof(DerivedItemType) <= kMaxItemSize,
   180→                  "DisplayItem subclass is larger than kMaxItemSize.");
   181→    static_assert(kAlignment % alignof(DerivedItemType) == 0,
   182→                  "Derived type requires stronger alignment.");
   183→    ItemSlot* result = AllocateItemSlot();
   184→    new (result) DerivedItemType(std::forward<Args>(args)...);
   185→    return *reinterpret_cast<DerivedItemType*>(result);
   186→  }
   187→
   188→  DisplayItem& AppendByMoving(DisplayItem& item) {
   189→    DCHECK(!item.IsTombstone());
   190→    return MoveItem(item, AllocateItemSlot());
   191→  }
   192→
   193→  DisplayItem& ReplaceLastByMoving(DisplayItem& item) {
   194→    DCHECK(!item.IsTombstone());
   195→    DisplayItem& last = back();
   196→    last.Destruct();
   197→    return MoveItem(item, reinterpret_cast<ItemSlot*>(&last));
   198→  }
   199→
   200→  void AppendSubsequenceByMoving(DisplayItemList& from,
   201→                                 wtf_size_t begin_index,
   202→                                 wtf_size_t end_index) {
   203→    DCHECK_GE(end_index, begin_index);
   204→    if (end_index == begin_index)
   205→      return;
   206→    DCHECK_LT(begin_index, from.size());
   207→    DCHECK_LE(end_index, from.size());
   208→
   209→    wtf_size_t count = end_index - begin_index;
   210→    ItemSlot* new_start_slot = AllocateItemSlots(count);
   211→    size_t bytes_to_move = reinterpret_cast<uint8_t*>(new_start_slot + count) -
   212→                           reinterpret_cast<uint8_t*>(new_start_slot);
   213→    memcpy(static_cast<void*>(new_start_slot),
   214→           static_cast<void*>(&from[begin_index]), bytes_to_move);
   215→    // This creates tombstones in the original items. Unlike AppendByMoving()
   216→    // for individual items, we won't use the moved items in a subsequence
   217→    // for raster invalidation, so we don't need to keep the other fields of
   218→    // the display items. DisplayItemTest.AllZeroIsTombstone ensures that the
   219→    // cleared items are tombstones.
   220→    memset(static_cast<void*>(&from[begin_index]), 0, bytes_to_move);
   221→  }
   222→
   223→#if DCHECK_IS_ON()
   224→  enum JsonOption {
   225→    kDefault,
   226→    // Only show a compact representation of the display item list. This flag
   227→    // cannot be used with kShowPaintRecords.
   228→    kCompact,
   229→    kShowPaintRecords,
   230→  };
   231→
   232→  static std::unique_ptr<JSONArray> DisplayItemsAsJSON(
   233→      const PaintArtifact&,
   234→      wtf_size_t first_item_index,
   235→      const Range<const_iterator>& display_items,
   236→      JsonOption);
   237→#else  // DCHECK_IS_ON()
   238→  enum JsonOption { kDefault };
   239→#endif
   240→
   241→ private:
   242→  static_assert(std::is_trivially_copyable<value_type>::value,
   243→                "DisplayItemList uses `memcpy` in several member functions; "
   244→                "the `value_type` used by it must be trivially copyable");
   245→
   246→  ItemSlot* AllocateItemSlot() { return &items_.emplace_back(); }
   247→
   248→  ItemSlot* AllocateItemSlots(wtf_size_t count) {
   249→    items_.Grow(size() + count);
   250→    return &items_.back() - (count - 1);
   251→  }
   252→
   253→  DisplayItem& MoveItem(DisplayItem& item, ItemSlot* new_item_slot) {
   254→    memcpy(static_cast<void*>(new_item_slot), static_cast<void*>(&item),
   255→           kMaxItemSize);
   256→
   257→    // Created a tombstone/"dead display item" that can be safely destructed but
   258→    // should never be used except for debugging and raster invalidation.
   259→    item.CreateTombstone();
   260→    DCHECK(item.IsTombstone());
   261→    // Original values for other fields are kept for debugging and raster
   262→    // invalidation.
   263→    DisplayItem& new_item = *reinterpret_cast<DisplayItem*>(new_item_slot);
   264→    DCHECK_EQ(item.VisualRect(), new_item.VisualRect());
   265→    DCHECK_EQ(item.GetRasterEffectOutset(), new_item.GetRasterEffectOutset());
   266→    return new_item;
   267→  }
   268→
   269→  ItemVector items_;
   270→};
   271→
   272→using DisplayItemIterator = DisplayItemList::const_iterator;
   273→using DisplayItemRange = DisplayItemList::Range<DisplayItemIterator>;
   274→
   275→}  // namespace blink
   276→
   277→#endif  // THIRD_PARTY_BLINK_RENDERER_PLATFORM_GRAPHICS_PAINT_DISPLAY_ITEM_LIST_H_
   278→

